import {
  useGetAccountQueryOptions,
  useGetPublicActionPageQueryOptions,
} from "@workspace/api-client/public";

export const Route = createFileRoute("/lead/$slug/$token")({
  component: RouteComponent,
  loader: async ({ context: { queryClient }, params: { slug, token } }) => {
    const actionPage = await queryClient.fetchQuery(
      useGetPublicActionPageQueryOptions({
        actionPageSlug: token,
        accountSlug: slug,
      }),
    );

    // pulls from cache first, use `fetchQuery` if we need to fetch
    const account = await queryClient.ensureQueryData(
      useGetAccountQueryOptions({
        accountUid: actionPage.account.id,
      }),
    );

    return { actionPage, account };
  },
});

function RouteComponent() {
